function normalizeJob(j){j={...j}; j.id=j.id||('job_'+Date.now()+Math.random().toString(16).slice(2)); j.ticketId=j.ticketId||makeTicket(); j.type=j.type||j.jobType||'Service Call'; j.status=j.status||defaultInitialStatus(j.type); j.systems=Array.isArray(j.systems)?j.systems:(j.system?[j.system]:['Other']); j.checklist=Array.isArray(j.checklist)?j.checklist:buildChecklist(j.systems,j.type); j.photos=Array.isArray(j.photos)?j.photos:[]; j.materials=Array.isArray(j.materials)?j.materials:[]; j.history=Array.isArray(j.history)?j.history:[]; normalizeStage(j); return j;}
function makeTicket(){let d=new Date(), y=d.getFullYear(), m=String(d.getMonth()+1).padStart(2,'0'), da=String(d.getDate()).padStart(2,'0'), t=String(Date.now()).slice(-5); return `SRV-${y}${m}${da}-${t}`;}
function defaultInitialStatus(type){return (workflowFor(type)||DEFAULT_WORKFLOW)[0]||'Assigned'}
function normalizeStage(j){let wf=workflowFor(j); if(wf.includes(j.status))return; const map={'Working':'Work In Progress','Report Draft':'Checklist Completed','Report Completed':'Report Generated','Awaiting Closure':'Coordinator Review'}; j.status=wf.includes(map[j.status])?map[j.status]:defaultInitialStatus(j.type)}
function buildChecklist(systems,type){let mode=(String(type).toLowerCase().includes('pm')||String(type).toLowerCase().includes('inspection'))?'pm':'service'; let rows=[]; (systems&&systems.length?systems:['Other']).forEach(sys=>{let lib=state.checklistLibrary[sys]||state.checklistLibrary.Other||BASE_CHECKLISTS.Other; (lib[mode]||lib.service||[]).forEach((text,i)=>rows.push({id:slug(sys+'_'+text+'_'+i),system:sys,text,status:'Pending',remarks:''}));}); return rows;}
function login(){let u=$('u').value.trim().toLowerCase(),p=$('p').value;let user=state.users.find(x=>x.active!==false&&x.username.toLowerCase()===u&&x.password===p); if(!user){$('loginMsg').textContent='Invalid username or password';return} current=user; $('login').classList.add('hidden'); $('app').classList.remove('hidden'); $('who').textContent=current.name; $('role').textContent=current.role; buildNav(); go('dashboard'); startRealtime();}
function logout(){unsubs.forEach(x=>{try{x()}catch(e){}});unsubs=[];current=null;$('app').classList.add('hidden');$('login').classList.remove('hidden')}
function navItems(){let base=['Dashboard','Jobs','Reports','Masters','Proposal / Quotation','Notifications']; if(current?.role==='Admin')base.push('Administration'); return base}
function key(x){return x.toLowerCase().replace(/[^a-z0-9]+/g,'_').replace(/^_|_$/g,'')}
function buildNav(){ $('nav').innerHTML=navItems().map(x=>`<button class="${activeView===key(x)?'active':''}" onclick="go('${key(x)}')">${x}</button>`).join('')}
function go(v){activeView=v;toggleMenu(false);buildNav();render()}
function toggleMenu(open){$('side')?.classList.toggle('open',open??!$('side').classList.contains('open')); $('drawerBackdrop')?.classList.toggle('show',$('side')?.classList.contains('open'))}
function setTitle(t,sub=VERSION){$('pageTitle').textContent=t;$('pageSubtitle').textContent=sub}
function render(){let el=$('view'); if(!current)return; ({dashboard:renderDashboard,jobs:renderJobs,reports:renderReports,masters:renderMasters,notifications:renderNotifications,proposal_quotation:renderProposal,administration:renderAdmin}[activeView]||renderDashboard)(el)}
function visibleJobs(){if(current.role==='Engineer')return state.jobs.filter(j=>j.assignedToId===current.id||j.visibleTo?.includes(current.id)); return state.jobs}
function assignableUsers(){return state.users.filter(u=>['Engineer','Supervisor','Coordinator'].includes(u.role)&&u.active!==false)}
function engineers(){return assignableUsers()}
function userRoleBadge(u){return u.role==='Engineer'?'Field Engineer':u.role}
function assigneeOptions(selected=''){let groups=['Engineer','Supervisor','Coordinator'];return groups.map(g=>{let arr=assignableUsers().filter(u=>u.role===g);if(!arr.length)return '';return `<optgroup label="${g}">${arr.map(u=>`<option value="${u.id}" ${selected===u.id?'selected':''}>${esc(u.name)} • ${esc(userRoleBadge(u))}</option>`).join('')}</optgroup>`}).join('')}
function workflowActionOptions(j){let opts=['Reassign / Update Notes',...workflowFor(j)];return opts.map(x=>`<option value="${esc(x)}" ${x===j.status?'selected':''}>${esc(x)}</option>`).join('')}
function statusPill(s){let c=s==='Closed'||s==='Customer Signed'?'ok':s==='Customer Sign-off'||s==='Assigned'||s==='PM Scheduled'||s==='Ticket Created'?'warn':s==='Coordinator Review'?'bad':'';return `<span class="pill ${c}">${esc(s||'Assigned')}</span>`}
function priorityPill(s){let c=s==='Critical'?'bad':s==='Urgent'?'warn':'ok'; return `<span class="pill ${c}">${esc(s||'Normal')}</span>`}
function renderDashboard(el){setTitle('Dashboard','Live operational summary');let jobs=visibleJobs().sort((a,b)=>(b.createdAt||'').localeCompare(a.createdAt||'')),open=jobs.filter(j=>j.status!=='Closed'),today=new Date().toISOString().slice(0,10); let bySystem={}; SYSTEMS.forEach(s=>bySystem[s]=jobs.filter(j=>j.systems?.includes(s)).length); el.innerHTML=`<div class="grid five"><div class="card stat"><small>Total Tickets</small><h2>${jobs.length}</h2></div><div class="card stat"><small>Open</small><h2>${open.length}</h2></div><div class="card stat"><small>Today</small><h2>${jobs.filter(j=>(j.createdAt||'').slice(0,10)===today).length}</h2></div><div class="card stat"><small>Coordinator Review</small><h2>${jobs.filter(j=>j.status==='Coordinator Review').length}</h2></div><div class="card stat"><small>Closed</small><h2>${jobs.filter(j=>j.status==='Closed').length}</h2></div></div><div class="grid two"><div class="card"><div class="sectionTitle"><h3>Workflow Pipeline</h3><button class="btn small secondary" onclick="go('jobs')">View Jobs</button></div>${workflowSummary(jobs)}</div><div class="card"><div class="sectionTitle"><h3>System-wise Load</h3><button class="btn small secondary" onclick="jobPanel='create';go('jobs')">+ New Ticket</button></div>${Object.entries(bySystem).filter(([s,c])=>c).map(([s,c])=>`<p><b>${esc(s)}</b> <span class="badge">${c}</span></p>`).join('')||'<div class="empty">No system data yet.</div>'}</div></div><div class="card"><div class="sectionTitle"><h3>Recent Tickets</h3><button class="btn small secondary" onclick="go('reports')">Reports</button></div>${jobTable(jobs.slice(0,8))}</div>`}
function workflowSummary(jobs){let all=[...new Set(jobs.flatMap(j=>workflowFor(j)))];return all.map(s=>`<p><b>${s}</b> <span class="badge">${jobs.filter(j=>j.status===s).length}</span></p>`).join('')}
function workflowLanes(jobs){let stages=[...new Set(jobs.flatMap(j=>workflowFor(j)))];return `<div class="workflowLanes">${stages.map(st=>{let arr=jobs.filter(j=>j.status===st).slice(0,8);return `<div class="lane"><h4>${esc(st)} <span>${jobs.filter(j=>j.status===st).length}</span></h4>${arr.map(j=>`<button class="laneTicket" onclick="openJob('${j.id}')"><b>${esc(j.ticketId)}</b><small>${esc(j.customerName)} • ${esc(j.assignedToName||'Unassigned')}</small></button>`).join('')||'<p class="muted smallText">No tickets</p>'}</div>`}).join('')}</div>`}
function statusRankFor(j,s){return workflowFor(j).indexOf(s)}
function quickStatus(id,status){let j=findJob(id);if(!j)return;if(!canMoveToStatus(j,status)){render();return}j.status=status;j.updatedAt=now();j.history=j.history||[];j.history.unshift({at:now(),by:current.name,action:'Status changed to '+status});saveLocal();syncJob(j);toast('Status updated: '+j.ticketId+' → '+status);render()}

function captureEditorInputs(j){
  if(!j)return;
  if($('ej_notes')){
    j.workNotes=$('ej_notes').value;
    j.scope=$('ej_scope')?.value||j.scope;
    j.customerRemarks=$('ej_customerremarks')?.value||j.customerRemarks;
    (j.checklist||[]).forEach((r,i)=>{r.status=$(`ck_status_${i}`)?.value||r.status;r.remarks=$(`ck_remarks_${i}`)?.value||r.remarks||''});
  }
}
function canChecklistComplete(j){captureEditorInputs(j);let pending=(j.checklist||[]).filter(r=>!r.status||r.status==='Pending').length;if(pending>0){toast('Complete all checklist items before advancing.');return false}return true}
function canCompleteReport(j){
  captureEditorInputs(j);
  let pending=(j.checklist||[]).filter(r=>!r.status||r.status==='Pending').length;
  if(pending>0){toast('Complete all checklist items before report completion.');return false}
  if(!(j.workNotes||'').trim()){toast('Enter work notes / root cause / rectification before report completion.');return false}
  if(!(j.photos||[]).length){toast('Upload at least one photo evidence before report completion.');return false}
  if(!j.engineerSignature){toast('Engineer digital signature is required before Generate Report. Open ticket and use Engineer Sign.');return false}
  return true
}
function reportReady(j){return reportGeneratedStages().includes(j.status)}
function canMoveToStatus(j,status){
  let cur=statusRankFor(j,j.status), nxt=statusRankFor(j,status);
  if(nxt<0){toast('This stage is not valid for this job type.');return false}
  if(nxt>cur+1){toast('Use Advance Workflow step-by-step.');return false}
  if(status==='Checklist Completed'&&!canChecklistComplete(j))return false;
  if(status==='Report Generated'&&!canCompleteReport(j))return false;
  if(status==='Customer Sign-off'&&!reportReady(j)){toast('Generate the report before sending customer sign-off.');return false}
  if(status==='Customer Signed'&&!j.signoffApproved){toast('Customer must approve through the secure sign-off link.');return false}
  if(status==='Report Shared'&&!canShareReport(j)){toast('Customer sign-off is required before sharing final report.');return false}
  return true
}
function completeReport(id,quiet=false){let j=findJob(id); if(!j)return; if(!canCompleteReport(j))return; if(!reportReady(j)){j.status='Report Generated';j.reportCompletedAt=now();j.reportGeneratedAt=now();j.history=j.history||[];j.history.unshift({at:now(),by:current?.name||'System',action:'Report generated and marked completed'});saveLocal();syncJob(j); if(!quiet)toast('Report completed. Send customer sign-off link next.')} }
function canShareReport(j){return !!j.signoffApproved && ['Customer Signed','Report Shared','Coordinator Review','Closed'].includes(j.status)}
function timelineJob(j){let wf=workflowFor(j);let i=Math.max(0,wf.indexOf(j.status));let pct=((i+1)/wf.length*100).toFixed(0);let extra=j.holdActive?` • HOLD: ${esc(j.holdReason||'')}`:(j.escalatedTo?` • Escalated to ${esc(j.escalatedTo)}`:'');return `<div class="progress"><div style="width:${pct}%"></div></div><small class="muted">${esc(j.type)} workflow • ${esc(j.status)} • ${pct}% complete${extra}</small>`}
function timeline(status){return `<div class="progress"><div style="width:50%"></div></div><small class="muted">${esc(status)}</small>`}
function actionAllowed(j,key){
  if(key==='accept')return !j.acceptedAt && ['Assigned','PM Scheduled','Ticket Created'].includes(j.status);
  if(key==='checkin')return !!j.acceptedAt && !j.checkedInAt;
  if(key==='generate')return !!j.checkedInAt && !j.reportGeneratedAt && !j.signoffApproved;
  if(key==='engineersign')return !!j.checkedInAt && !j.engineerSignature && !j.reportGeneratedAt;
  if(key==='review')return !!j.reportGeneratedAt && !!j.engineerSignature && !j.signoffApproved;
  if(key==='close')return !!j.signoffApproved && j.status!=='Closed';
  if(key==='checkout')return !!j.checkedInAt && !j.checkedOutAt;
  if(key==='hold')return j.status!=='Closed' && !j.holdActive;
  if(key==='escalate')return j.status!=='Closed';
  return false;
}
function smartActionBtn(j){
  if(j.holdActive)return `<button class="btn small warn" onclick="releaseHoldTicket('${j.id}',true)">Release Hold</button><button class="btn small ghost" onclick="openJob('${j.id}')">View Ticket</button>`;
  if(actionAllowed(j,'accept'))return `<button class="btn small ok" onclick="acceptTicket('${j.id}',true)">Accept Ticket</button>`;
  if(actionAllowed(j,'checkin'))return `<button class="btn small ok" onclick="checkInTicket('${j.id}',true)">Check-In</button>`;
  if(actionAllowed(j,'engineersign'))return `<button class="btn small ok" onclick="openJob('${j.id}')">Engineer Sign</button>`;
  if(actionAllowed(j,'generate'))return `<button class="btn small ok" onclick="generateReport('${j.id}')">Generate Report</button>`;
  if(actionAllowed(j,'review'))return `<button class="btn small ok" onclick="createSignoffLink('${j.id}')">Send Customer Review</button>`;
  if(j.signoffToken && !j.signoffApproved)return `<button class="btn small secondary" onclick="createSignoffLink('${j.id}')">Copy Review Link</button>`;
  if(j.signoffApproved && !j.finalSharedAt)return `<button class="btn small ok" onclick="shareWhatsApp('${j.id}')">Share Final Report</button>`;
  if(actionAllowed(j,'close'))return `<button class="btn small ok" onclick="closeTicket('${j.id}',true)">Close Ticket</button>`;
  if(actionAllowed(j,'checkout'))return `<button class="btn small secondary" onclick="checkOutTicket('${j.id}',true)">Check-Out</button>`;
  return `<span class="pill ok">Completed</span>`
}
function nextActionBtn(j){return smartActionBtn(j)}
function jobTable(jobs){if(!jobs.length)return '<div class="empty">No jobs found.</div>';return `<div class="jobList">${jobs.map(j=>`<article class="jobCard"><div class="jobTop"><div><h3>${esc(j.ticketId)}</h3><p>${esc(j.customerName)} • ${esc(j.siteName||'')}</p></div><div>${statusPill(j.status)} ${priorityPill(j.priority)}</div></div><div class="jobMeta"><span><b>Visit Type</b>${esc(j.type)}</span><span><b>Systems</b>${(j.systems||[]).map(x=>`<em>${esc(x)}</em>`).join('')}</span><span><b>Assigned To</b>${esc(j.assignedToName||'Unassigned')}<small>${esc(j.assignedToRole||'')}</small></span></div>${timelineJob(j)}<div class="jobActions"><button class="btn small" onclick="openJob('${j.id}')">Ticket Command Center</button>${smartActionBtn(j)}${actionAllowed(j,'hold')?`<button class="btn small warn" onclick="holdTicket('${j.id}',true)">Hold</button>`:''}<button class="btn small ghost" onclick="escalateTicket('${j.id}',true)">Escalate</button><button class="btn small ghost" onclick="showReport('${j.id}')">Report</button><button class="btn small ghost" onclick="exportJobExcel('${j.id}')">Excel</button>${canShareReport(j)?`<button class="btn small ghost" onclick="shareEmail('${j.id}')">Email</button>`:''}</div></article>`).join('')}</div>`}
function renderJobs(el){setTitle('Jobs Command Center','Create, assign, execute, sign-off and close tickets');let jobs=visibleJobs().sort((a,b)=>(b.createdAt||'').localeCompare(a.createdAt||''));let listActive=jobPanel==='list'?'active':'';let createActive=jobPanel==='create'?'active':'';el.innerHTML=`<div class="miniTabs noPrint stickyTabs"><button class="${listActive}" onclick="jobPanel='list';render()">Ticket Board</button><button class="${createActive}" onclick="jobPanel='create';render()">+ New Ticket</button><button onclick="go('reports')">Report Library</button><button onclick="exportJobsExcel()">Export Excel</button></div>${jobPanel==='create'?createJobPanel():`<div class="grid five compactStats"><div class="card stat"><small>Total</small><h2>${jobs.length}</h2></div><div class="card stat"><small>Open</small><h2>${jobs.filter(j=>j.status!=='Closed').length}</h2></div><div class="card stat"><small>In Progress</small><h2>${jobs.filter(j=>['Work In Progress','PM Activity Completed','Diagnosis','Installation Started','Testing & Commissioning','Survey In Progress','Audit In Progress'].includes(j.status)).length}</h2></div><div class="card stat"><small>Report Ready</small><h2>${jobs.filter(j=>j.status==='Report Generated').length}</h2></div><div class="card stat"><small>Sign-off</small><h2>${jobs.filter(j=>['Customer Sign-off','Customer Signed'].includes(j.status)).length}</h2></div></div><div class="card filterCard"><div class="sectionTitle"><h3>Smart Filters</h3><button class="btn small secondary" onclick="jobPanel='create';render()">+ Create Ticket</button><button class="btn small ghost" onclick="exportJobsExcel()">Export All Excel</button></div><div class="toolbar"><div><label>Search</label><input id="f_q" placeholder="Ticket, customer, site, engineer, system" oninput="filterJobs()"></div><div><label>Status</label><select id="f_status" onchange="filterJobs()"><option value="">All Status</option>${STATUSES.map(s=>`<option>${s}</option>`).join('')}</select></div><div><label>Job Type</label><select id="f_type" onchange="filterJobs()"><option value="">All Type</option>${JOB_TYPES.map(s=>`<option>${s}</option>`).join('')}</select></div><div><label>System</label><select id="f_system" onchange="filterJobs()"><option value="">All Systems</option>${SYSTEMS.map(s=>`<option>${s}</option>`).join('')}</select></div></div></div><div class="card"><div class="sectionTitle"><h3>Smart Dispatch Pipeline</h3><span class="badge">Drag-free stage view</span></div>${workflowLanes(jobs)}</div><div class="card"><div class="sectionTitle"><h3>Ticket Board</h3><span class="badge" id="jobCount">${jobs.length}</span></div><div id="jobsOut">${jobTable(jobs)}</div></div>`}`}
function createJobPanel(){let ticket=makeTicket();return `<div class="card createPanel"><div class="sectionTitle"><div><h3>New Job / Ticket</h3><p class="muted">Select system + visit type to auto-load the right checklist and report template.</p></div><button class="btn small secondary" onclick="jobPanel='list';render()">Back to Ticket Board</button></div><div class="grid two"><div><label>Ticket Number</label><input id="cj_ticket" value="${ticket}"></div><div><label>Priority</label><select id="cj_priority">${PRIORITIES.map(x=>`<option>${x}</option>`).join('')}</select></div></div><div class="grid two"><div><label>Customer</label><input id="cj_customer" list="customersList" onchange="updateSiteList()"><datalist id="customersList">${state.customers.map(c=>`<option value="${esc(c.name)}">`).join('')}</datalist></div><div><label>Site</label><input id="cj_site" list="sitesList"><datalist id="sitesList">${state.sites.map(s=>`<option value="${esc(s.name)}">`).join('')}</datalist></div></div><div class="grid three"><div><label>Job Type</label><select id="cj_type" onchange="previewChecklist()">${JOB_TYPES.map(x=>`<option>${x}</option>`).join('')}</select></div><div><label>Assigned Engineer</label><select id="cj_eng">${assigneeOptions()}</select></div><div><label>Due Date</label><input id="cj_due" type="date"></div></div><label>Systems</label><div class="systemPicker">${SYSTEMS.map(s=>`<label><input type="checkbox" class="cj_sys" value="${esc(s)}" onchange="previewChecklist()"><span>${esc(s)}</span></label>`).join('')}</div><label>Scope / Complaint / Visit Purpose</label><textarea id="cj_scope" placeholder="Describe complaint, PM visit purpose, survey scope, installation scope etc."></textarea><div class="actions"><button class="btn ok" onclick="saveJob()">Create & Assign Ticket</button><button class="btn secondary" onclick="previewChecklist()">Preview Checklist</button></div></div><div class="card"><h3>Auto Checklist Preview</h3><div id="checkPreview" class="empty">Select system and job type to preview checklist.</div></div>`}
function filterJobs(){let q=$('f_q').value.toLowerCase(),st=$('f_status').value,tp=$('f_type').value,sys=$('f_system').value;let jobs=visibleJobs().filter(j=>{let hay=[j.ticketId,j.customerName,j.siteName,j.assignedToName,j.type,j.status,(j.systems||[]).join(' ')].join(' ').toLowerCase();return (!q||hay.includes(q))&&(!st||j.status===st)&&(!tp||j.type===tp)&&(!sys||(j.systems||[]).includes(sys))}).sort((a,b)=>(b.createdAt||'').localeCompare(a.createdAt||'')); $('jobCount').textContent=jobs.length; $('jobsOut').innerHTML=jobTable(jobs)}
function renderCreate(el){jobPanel='create';renderJobs(el)}
function updateSiteList(){let c=$('cj_customer').value; $('sitesList').innerHTML=state.sites.filter(s=>!c||s.customerName===c).map(s=>`<option value="${esc(s.name)}">`).join('')}
function selectedSystems(){return [...document.querySelectorAll('.cj_sys:checked')].map(x=>x.value)}
function previewChecklist(){let systems=selectedSystems();let type=$('cj_type')?.value||'Service Call';let rows=buildChecklist(systems.length?systems:['Other'],type); $('checkPreview').innerHTML=`<p><b>${esc(type)}</b> template for <b>${systems.map(esc).join(', ')||'Other'}</b></p><ol>${rows.map(r=>`<li>${esc(r.system)} - ${esc(r.text)}</li>`).join('')}</ol>`}
async function saveJob(){let systems=selectedSystems(); if(!systems.length){toast('Select at least one system.');return} let eng=state.users.find(u=>u.id===$('cj_eng').value)||{}; let j=normalizeJob({id:'job_'+Date.now(),ticketId:$('cj_ticket').value.trim()||makeTicket(),customerName:$('cj_customer').value.trim(),siteName:$('cj_site').value.trim(),type:$('cj_type').value,priority:$('cj_priority').value,dueDate:$('cj_due').value,scope:$('cj_scope').value.trim(),systems,assignedToId:eng.id,assignedToName:eng.name,assignedToRole:eng.role,status:defaultInitialStatus($('cj_type').value),visibleTo:[eng.id],createdBy:current.id,createdByName:current.name,createdAt:now(),updatedAt:now(),history:[{at:now(),by:current.name,action:'Created job'}]}); if(!j.customerName||!j.siteName){toast('Customer and site are required.');return} state.jobs.unshift(j); saveLocal(); if(cloudReady)try{let ref=await db.collection('jobs').add(j);j.firestoreId=ref.id;saveLocal()}catch(e){console.warn(e)} await notify(j,`New job assigned: ${j.ticketId} - ${j.customerName}`,'ticket_assigned'); toast('Job created: '+j.ticketId); jobPanel='list'; go('jobs')}
function findJob(id){return state.jobs.find(j=>j.id===id||j.ticketId===id||j.firestoreId===id)}
function openJob(id){let j=findJob(id); if(!j)return; setTitle('Manage Ticket '+j.ticketId,'Workflow, checklist, evidence, material and report preview'); $('view').innerHTML=jobEditor(j); setTimeout(initEngSigCanvas,50);}
function jobEditor(j){return `<div class="card"><div class="sectionTitle"><div><h3>${esc(j.ticketId)} - ${esc(j.customerName)}</h3><p class="muted">${esc(j.siteName)} • ${esc(j.type)} • ${esc((j.systems||[]).join(', '))}</p></div><div>${statusPill(j.status)} ${priorityPill(j.priority)}</div></div>${timelineJob(j)}<div class="guidedPanel"><div><b>Next Best Action</b><p class="muted">Only approved field actions are shown: Accept, Check-In, Generate Report, Engineer Sign, Send Customer Review, Close Ticket, Check-Out, Hold and Escalate. Backend updates stages automatically.</p></div><div class="actions">${smartActionBtn(j)}${actionAllowed(j,'hold')?`<button class="btn warn" onclick="holdTicket('${j.id}')">Hold</button>`:''}<button class="btn ghost" onclick="escalateTicket('${j.id}')">Escalate</button></div></div><div class="grid two"><div><label>Assign / Escalate To</label><select id="ej_eng" onchange="autoSaveJob('${j.id}')">${assigneeOptions(j.assignedToId)}</select></div><div><label>Field Timing</label><div class="timingBox"><span>Check-In: ${esc((j.checkedInAt||'Pending').replace('T',' ').slice(0,16))}</span><span>Check-Out: ${esc((j.checkedOutAt||'Pending').replace('T',' ').slice(0,16))}</span></div></div></div><label>Scope / Complaint</label><textarea id="ej_scope" oninput="debouncedAutoSave('${j.id}')">${esc(j.scope||'')}</textarea><label>Work Notes / Root Cause / Rectification</label><textarea id="ej_notes" oninput="debouncedAutoSave('${j.id}')">${esc(j.workNotes||'')}</textarea><label>Customer Remarks / Recommendations</label><textarea id="ej_customerremarks" oninput="debouncedAutoSave('${j.id}')">${esc(j.customerRemarks||'')}</textarea><div id="draftSaveState" class="autoSaveState">✓ Auto-save enabled</div><div class="actions"><button class="btn secondary" onclick="saveJobEdit('${j.id}')">Save Now</button><button class="btn ok" onclick="generateReport('${j.id}')">Generate Engineer Signed Report</button><button class="btn ghost" onclick="printReport('${j.id}')">Export PDF</button>${canShareReport(j)?`<button class="btn secondary" onclick="shareWhatsApp('${j.id}')">WhatsApp Final PDF</button>`:`<button class="btn secondary" onclick="toast('Generate report, engineer sign, then send customer approval first.')">Share Locked</button>`}<button class="btn secondary" onclick="go('jobs')">Back</button></div></div><div class="grid two"><div class="card"><h3>Checklist Filling</h3><p class="muted">Every change is auto-saved. Use OK / Not OK / N.A. Add remarks for failed items.</p><div id="ckRows">${checklistRows(j)}</div><div class="toolbar"><input id="newCkText" placeholder="Add custom checklist point"><select id="newCkSystem">${(j.systems||['Other']).map(s=>`<option>${esc(s)}</option>`).join('')}</select><button class="btn secondary" onclick="addChecklistItem('${j.id}')">Add Point</button></div></div><div class="card"><h3>Photo Evidence</h3><input id="photoInput" type="file" multiple accept="image/*" onchange="previewPhotos(this)"><div id="photoPreview" class="preview">${photoHtml(j.photos)}</div><button class="btn secondary" onclick="savePhotos('${j.id}')">Save Photos to Ticket</button><h3>Engineer Digital Signature</h3><p class="muted">Required before sending report for customer review.</p>${j.engineerSignature?`<div class="signedSeal"><b>Engineer Signed</b><span>${esc(j.engineerSignedBy||j.assignedToName||current.name)}</span><span>${esc((j.engineerSignedAt||'').replace('T',' ').slice(0,16))}</span><img class="sigImg" src="${j.engineerSignature}"></div>`:`<canvas id="engSigCanvas" class="sigCanvas" width="620" height="190"></canvas><div class="actions"><button class="btn small secondary" onclick="clearEngSig()">Clear</button><button class="btn small ok" onclick="saveEngineerSignature('${j.id}')">Save Engineer Signature</button></div>`}<h3>Materials Used</h3><div id="matRows">${materialRows(j)}</div><div class="grid three"><input id="matDesc" placeholder="Material"><input id="matQty" placeholder="Qty"><input id="matRemarks" placeholder="Remarks"></div><button class="btn secondary" onclick="addMaterial('${j.id}')">Add Material</button></div></div><div class="card"><h3>Ticket History</h3>${(j.history||[]).map(h=>`<p>• <b>${esc((h.at||'').replace('T',' ').slice(0,16))}</b> - ${esc(h.by)}: ${esc(h.action)}</p>`).join('')||'<p class="muted">No history yet.</p>'}</div>`}
function checklistRows(j){return (j.checklist||[]).map((r,i)=>`<div class="checkRow"><div class="ckTitle">${esc(r.system)} - ${esc(r.text)}</div><select id="ck_status_${i}" onchange="autoSaveJob('${j.id}')"><option ${r.status==='Pending'?'selected':''}>Pending</option><option ${r.status==='OK'?'selected':''}>OK</option><option ${r.status==='Not OK'?'selected':''}>Not OK</option><option ${r.status==='N.A.'?'selected':''}>N.A.</option></select><input id="ck_remarks_${i}" placeholder="Remarks" value="${esc(r.remarks||'')}" oninput="debouncedAutoSave('${j.id}')"><button class="remove" onclick="removeChecklistItem('${j.id}',${i})">×</button></div>`).join('')}
let autoSaveTimers={};
function debouncedAutoSave(id){if(autoSaveTimers[id])clearTimeout(autoSaveTimers[id]);let el=$('draftSaveState'); if(el)el.textContent='Saving draft...'; autoSaveTimers[id]=setTimeout(()=>autoSaveJob(id),650)}
function autoSaveJob(id){let j=findJob(id); if(!j)return; let eng=state.users.find(u=>u.id===$('ej_eng')?.value)||{}; if(eng.id){j.assignedToId=eng.id;j.assignedToName=eng.name;j.assignedToRole=eng.role;j.visibleTo=[eng.id]} captureEditorInputs(j); j.updatedAt=now(); saveLocal(); syncJob(j); let el=$('draftSaveState'); if(el)el.textContent='✓ Draft auto-saved '+new Date().toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'});}
function saveJobEdit(id){let j=findJob(id); if(!j)return; autoSaveJob(id); j.history=j.history||[];j.history.unshift({at:now(),by:current.name,action:'Saved ticket draft'});saveLocal();syncJob(j);toast('Draft saved');}
function advanceToStage(j,stage,action){if(!stage)return; setStage(j,stage,action); saveLocal(); syncJob(j); notify(j,`${j.ticketId} moved to ${j.status}`,'workflow');}
function moveNext(id,stayBoard=false){let j=findJob(id); let next=nextStage(j); if(!next)return; if(!canMoveToStatus(j,next)){stayBoard?render():openJob(id);return} advanceToStage(j,next,'Moved to '+next); toast(j.ticketId+' moved to '+j.status); stayBoard?render():openJob(id)}
function acceptTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; j.acceptedAt=now(); let st=firstMatchingStage(j,['Accepted'])||nextStage(j); advanceToStage(j,st,'Ticket accepted'); toast('Ticket accepted'); stayBoard?render():openJob(id)}
function checkInTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; j.checkedInAt=now(); let st=firstMatchingStage(j,['Work In Progress','Diagnosis','Installation Started','Survey In Progress','Audit In Progress','PM Activity Completed'])||nextStage(j); advanceToStage(j,st,'Engineer checked in; work started'); toast('Check-in done. Status updated to '+j.status); stayBoard?render():openJob(id)}
function checkOutTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; j.checkedOutAt=now(); j.history=j.history||[]; j.history.unshift({at:now(),by:current.name,action:'Engineer checked out'}); saveLocal(); syncJob(j); toast('Check-out recorded'); stayBoard?render():openJob(id)}
function closeTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; if(!j.signoffApproved){toast('Customer approval required before ticket closure.');return} setStage(j,'Closed','Ticket closed'); saveLocal(); syncJob(j); notify(j,`${j.ticketId} closed`,'closed');toast('Ticket closed'); stayBoard?render():openJob(id)}
function holdTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; let reason=prompt('Hold reason: Waiting Material / Waiting Customer / Waiting OEM / Waiting Access / Other', j.holdReason||'Waiting Material'); if(!reason)return; j.holdActive=true; j.holdReason=reason; j.holdAt=now(); j.history=j.history||[]; j.history.unshift({at:now(),by:current.name,action:'Ticket placed on hold: '+reason}); saveLocal(); syncJob(j); notify(j,`${j.ticketId} placed on hold: ${reason}`,'internal_hold');toast('Ticket moved to Hold'); stayBoard?render():openJob(id)}
function releaseHoldTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; j.holdActive=false; j.holdReleasedAt=now(); j.history=j.history||[]; j.history.unshift({at:now(),by:current.name,action:'Hold released'}); saveLocal(); syncJob(j); toast('Hold released'); stayBoard?render():openJob(id)}
function escalateTicket(id,stayBoard=false){let j=findJob(id); if(!j)return; let to=prompt('Escalate to: Supervisor / Coordinator / Admin / OEM / Customer', j.escalatedTo||'Supervisor'); if(!to)return; let note=prompt('Escalation note / reason', j.escalationNote||'')||''; j.escalatedTo=to; j.escalationNote=note; j.escalatedAt=now(); j.history=j.history||[]; j.history.unshift({at:now(),by:current.name,action:'Ticket escalated to '+to+(note?': '+note:'')}); saveLocal(); syncJob(j); notify(j,`${j.ticketId} escalated to ${to}`,'escalated'); toast('Ticket escalated'); stayBoard?render():openJob(id)}

function addChecklistItem(id){let j=findJob(id), text=$('newCkText').value.trim(); if(!text)return; j.checklist.push({id:slug(text),system:$('newCkSystem').value,text,status:'Pending',remarks:''}); saveLocal(); openJob(id)}
function removeChecklistItem(id,i){let j=findJob(id); j.checklist.splice(i,1); saveLocal(); openJob(id)}
let engSigDirty=false;
function initEngSigCanvas(){let c=document.getElementById('engSigCanvas');if(!c)return;let ctx=c.getContext('2d'),drawing=false,last=null;ctx.lineWidth=2.5;ctx.lineCap='round';function pos(e){let r=c.getBoundingClientRect(),t=e.touches?e.touches[0]:e;return{x:(t.clientX-r.left)*c.width/r.width,y:(t.clientY-r.top)*c.height/r.height}}function start(e){drawing=true;last=pos(e);e.preventDefault()}function move(e){if(!drawing)return;let p=pos(e);ctx.beginPath();ctx.moveTo(last.x,last.y);ctx.lineTo(p.x,p.y);ctx.stroke();last=p;engSigDirty=true;e.preventDefault()}function end(){drawing=false}c.addEventListener('mousedown',start);c.addEventListener('mousemove',move);window.addEventListener('mouseup',end);c.addEventListener('touchstart',start,{passive:false});c.addEventListener('touchmove',move,{passive:false});c.addEventListener('touchend',end)}
function clearEngSig(){let c=document.getElementById('engSigCanvas');if(c)c.getContext('2d').clearRect(0,0,c.width,c.height);engSigDirty=false}
function saveEngineerSignature(id){let j=findJob(id),c=document.getElementById('engSigCanvas');if(!j||!c)return;if(!engSigDirty){toast('Please draw engineer signature first.');return}j.engineerSignature=c.toDataURL('image/png');j.engineerSignedBy=current.name;j.engineerSignedAt=now();j.history=j.history||[];j.history.unshift({at:now(),by:current.name,action:'Engineer digitally signed draft report'});saveLocal();syncJob(j);toast('Engineer signature saved');openJob(id)}
let pendingPhotos=[];
function previewPhotos(input){pendingPhotos=[];let files=[...input.files].slice(0,8);let done=0; if(!files.length)return; files.forEach(f=>{let r=new FileReader(); r.onload=e=>{pendingPhotos.push({name:f.name,data:e.target.result,createdAt:now()}); done++; if(done===files.length) $('photoPreview').innerHTML=photoHtml([...(findJob(activeJobId())?.photos||[]),...pendingPhotos]);}; r.readAsDataURL(f);});}
function activeJobId(){let h=document.querySelector('h3')?.textContent||'';return (h.match(/SRV-[0-9]+-[0-9]+/)||[])[0]}
function photoHtml(photos){return (photos||[]).map((p,i)=>`<div class="previewCard"><img src="${esc(p.data||p.url||'')}" alt="photo"><small>${esc(p.name||('Photo '+(i+1)))}</small></div>`).join('')||'<div class="empty">No photos uploaded.</div>'}
function savePhotos(id){let j=findJob(id); if(!pendingPhotos.length){toast('No new photo selected.');return} j.photos=[...(j.photos||[]),...pendingPhotos]; pendingPhotos=[];j.history=j.history||[];j.history.unshift({at:now(),by:current.name,action:'Photo evidence added'});saveLocal();syncJob(j);openJob(id);toast('Photos saved to ticket')}
function materialRows(j){return `<table><thead><tr><th>Material</th><th>Qty</th><th>Remarks</th></tr></thead><tbody>${(j.materials||[]).map(m=>`<tr><td>${esc(m.desc)}</td><td>${esc(m.qty)}</td><td>${esc(m.remarks)}</td></tr>`).join('')||'<tr><td colspan="3">No material added.</td></tr>'}</tbody></table>`}
function addMaterial(id){let j=findJob(id); let desc=$('matDesc').value.trim(); if(!desc)return; j.materials.push({desc,qty:$('matQty').value,remarks:$('matRemarks').value}); saveLocal(); openJob(id)}
async function syncJob(j){if(cloudReady)try{if(j.firestoreId)await db.collection('jobs').doc(j.firestoreId).set(j,{merge:true});else{let ref=await db.collection('jobs').add(j);j.firestoreId=ref.id;saveLocal()}}catch(e){console.warn(e)}}
function renderReports(el){setTitle('Reports','Ticket-number based service report output');let jobs=visibleJobs().sort((a,b)=>(b.createdAt||'').localeCompare(a.createdAt||'')); el.innerHTML=`<div class="card"><h3>Find Report by Ticket Number</h3><div class="toolbar"><input id="r_ticket" placeholder="Enter ticket number e.g. SRV-20260621-12345"><button class="btn" onclick="reportByTicket()">Preview Report</button><button class="btn secondary" onclick="go('jobs')">Browse Jobs</button></div></div><div class="card"><h3>Latest Ticket Reports</h3>${jobTable(jobs.slice(0,20))}</div><div id="reportOut"></div>`}
function reportByTicket(){let t=$('r_ticket').value.trim();let j=findJob(t); if(!j){toast('Ticket not found');return} generateReport(j.id)}
function reportHtml(j){let ok=(j.checklist||[]).filter(r=>r.status==='OK').length, notok=(j.checklist||[]).filter(r=>r.status==='Not OK').length, pending=(j.checklist||[]).filter(r=>!r.status||r.status==='Pending').length;let ck=(j.checklist||[]).map((r,i)=>`<tr><td>${i+1}</td><td>${esc(r.system)}</td><td>${esc(r.text)}</td><td><span class="rStatus ${slug(r.status)}">${esc(r.status||'Pending')}</span></td><td>${esc(r.remarks||'')}</td></tr>`).join(''); let mats=(j.materials||[]).map((m,i)=>`<tr><td>${i+1}</td><td>${esc(m.desc)}</td><td>${esc(m.qty)}</td><td>${esc(m.remarks)}</td></tr>`).join(''); return `<div class="reportPaper proReport"><div class="reportHeaderBand"><div class="brandReport"><img src="assets/logo.png" alt="Payaswini Integrated Solutions"><div><h1>${esc(reportTitle(j))}</h1><p>Ticket Based Field Service Report</p></div></div><div class="ticketBox"><span>Ticket No.</span><b>${esc(j.ticketId)}</b><small>${esc((j.createdAt||now()).replace('T',' ').slice(0,16))}</small></div></div><div class="reportSummary"><div><b>Customer</b><span>${esc(j.customerName)}</span></div><div><b>Site</b><span>${esc(j.siteName)}</span></div><div><b>Job Type</b><span>${esc(j.type)}</span></div><div><b>Systems</b><span>${esc((j.systems||[]).join(', '))}</span></div><div><b>Workflow Stage</b><span>${esc(j.status)}</span></div><div><b>Report Status</b><span>${reportReady(j)?'Completed':'Draft / Pending'}</span></div><div><b>Engineer</b><span>${esc(j.assignedToName)}</span></div></div><div class="reportKpis"><div><b>${(j.checklist||[]).length}</b><span>Checklist Items</span></div><div><b>${ok}</b><span>OK</span></div><div><b>${notok}</b><span>Not OK</span></div><div><b>${pending}</b><span>Pending</span></div></div><h3>Scope / Complaint</h3><p class="reportBoxText">${esc(j.scope||'')}</p><h3>Work Done / Root Cause / Rectification</h3><p class="reportBoxText">${esc(j.workNotes||'')}</p><h3>Checklist Observation</h3><table class="proposalTable"><thead><tr><th>Sr</th><th>System</th><th>Activity / Check Point</th><th>Status</th><th>Remarks</th></tr></thead><tbody>${ck||'<tr><td colspan="5">No checklist</td></tr>'}</tbody></table><h3>Materials Used</h3><table class="proposalTable"><thead><tr><th>Sr</th><th>Item</th><th>Qty</th><th>Remarks</th></tr></thead><tbody>${mats||'<tr><td colspan="4">No material consumed.</td></tr>'}</tbody></table><h3>Customer Remarks / Recommendations</h3><p class="reportBoxText">${esc(j.customerRemarks||'')}</p>${customerSignoffBlock(j)}<h3>Photo Evidence</h3><div class="photoGrid reportPhotos">${photoHtml(j.photos)}</div>${reportSignatureSection(j)}<div class="reportFooter">Generated from PISL FieldOps Enterprise v40.5 • ${esc(j.ticketId)}</div><div class="actions noPrint"><button class="btn" onclick="printReport('${j.id}')">Export PDF</button><button class="btn secondary" onclick="exportJobExcel('${j.id}')">Export Excel</button>${canShareReport(j)?`<button class="btn secondary" onclick="shareWhatsApp('${j.id}')">Share WhatsApp</button>`:`<button class="btn secondary" onclick="createSignoffLink('${j.id}')">Send Customer Sign-off</button>`}</div></div>`}
function reportTitle(j){let sys=(j.systems||['General'])[0]; let t=String(j.type||'Service'); if(t.includes('PM'))return `${sys} Preventive Maintenance Report`; if(t.includes('Breakdown')||t.includes('Emergency'))return `${sys} Breakdown / Emergency Service Report`; if(t.includes('Installation'))return `${sys} Installation & Handover Report`; if(t.includes('Commissioning'))return `${sys} Testing & Commissioning Report`; if(t.includes('Rectification'))return `${sys} Rectification Report`; if(t.includes('Audit'))return `${sys} Audit Report`; if(t.includes('Inspection'))return `${sys} Inspection Report`; if(t.includes('Survey'))return `${sys} Site Survey Report`; if(t.includes('Warranty'))return `${sys} Warranty Service Report`; if(t.includes('Quotation'))return `${sys} Site Visit / Quotation Report`; return `${sys} Field Service Report`}
function generateReport(id){let j=findJob(id); if(!j)return; if(!canCompleteReport(j))return; completeReport(id,true);showReport(id);toast('Engineer signed report generated. Send for customer review next.')}
function showReport(id){let j=findJob(id); if(!j)return; setTitle('Report Preview '+j.ticketId,'Professional ticket-wise output based on ticket number'); $('view').innerHTML=`<div class="noPrint actions"><button class="btn secondary" onclick="go('jobs')">Back to Jobs</button><button class="btn ok" onclick="printReport('${j.id}')">Export PDF</button><button class="btn secondary" onclick="exportJobExcel('${j.id}')">Export Excel</button>${canShareReport(j)?`<button class="btn secondary" onclick="shareWhatsApp('${j.id}')">Share WhatsApp</button>`:(reportReady(j)?`<button class="btn secondary" onclick="createSignoffLink('${j.id}')">Send Customer Sign-off</button>`:'')}</div>${reportHtml(j)}`}
function printReport(id){let j=findJob(id); if(!j)return; captureEditorInputs(j); if(!reportReady(j)&&!canCompleteReport(j))return; completeReport(id,true);let w=window.open('','_blank');w.document.write(`<!doctype html><html><head><title>${esc(reportFileName(j))}</title><link rel="stylesheet" href="${new URL('css/main.css',location.href).href}"></head><body>${reportHtml(j).replaceAll('src="assets/logo.png"','src="'+new URL('assets/logo.png',location.href).href+'"')}<script>setTimeout(()=>print(),700)<\/script></body></html>`);w.document.close()}

function downloadFile(name,content,type){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([content],{type}));a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function excelCell(v){return String(v??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}
function jobExcelHtml(j){let rows=[['Ticket',j.ticketId],['Customer',j.customerName],['Site',j.siteName],['Type',j.type],['Systems',(j.systems||[]).join(', ')],['Status',j.status],['Priority',j.priority],['Assigned To',j.assignedToName],['Created',(j.createdAt||'').replace('T',' ').slice(0,16)],['Scope',j.scope||''],['Work Notes',j.workNotes||''],['Customer Remarks',j.customerRemarks||'']];let ck=(j.checklist||[]).map((r,i)=>`<tr><td>${i+1}</td><td>${excelCell(r.system)}</td><td>${excelCell(r.text)}</td><td>${excelCell(r.status||'Pending')}</td><td>${excelCell(r.remarks||'')}</td></tr>`).join('');let mat=(j.materials||[]).map((m,i)=>`<tr><td>${i+1}</td><td>${excelCell(m.desc)}</td><td>${excelCell(m.qty)}</td><td>${excelCell(m.remarks)}</td></tr>`).join('');return `<html><head><meta charset="utf-8"></head><body><h2>Payaswini FieldOps Ticket Report - ${excelCell(j.ticketId)}</h2><table border="1">${rows.map(r=>`<tr><th>${excelCell(r[0])}</th><td>${excelCell(r[1])}</td></tr>`).join('')}</table><h3>Checklist</h3><table border="1"><tr><th>Sr</th><th>System</th><th>Check Point</th><th>Status</th><th>Remarks</th></tr>${ck}</table><h3>Materials Used</h3><table border="1"><tr><th>Sr</th><th>Item</th><th>Qty</th><th>Remarks</th></tr>${mat}</table></body></html>`}
function exportJobExcel(id){let j=findJob(id);if(!j)return;downloadFile(`${j.ticketId}_Field_Service_Report.xls`,jobExcelHtml(j),'application/vnd.ms-excel')}
function exportJobsExcel(){let jobs=visibleJobs();let head=['Ticket','Customer','Site','Type','Systems','Status','Priority','Assigned To','Created','Due Date'];let trs=jobs.map(j=>`<tr><td>${excelCell(j.ticketId)}</td><td>${excelCell(j.customerName)}</td><td>${excelCell(j.siteName)}</td><td>${excelCell(j.type)}</td><td>${excelCell((j.systems||[]).join(', '))}</td><td>${excelCell(j.status)}</td><td>${excelCell(j.priority)}</td><td>${excelCell(j.assignedToName)}</td><td>${excelCell((j.createdAt||'').replace('T',' ').slice(0,16))}</td><td>${excelCell(j.dueDate||'')}</td></tr>`).join('');downloadFile(`PISL_Ticket_Register_${new Date().toISOString().slice(0,10)}.xls`,`<html><head><meta charset="utf-8"></head><body><h2>PISL FieldOps Ticket Register</h2><table border="1"><tr>${head.map(h=>`<th>${h}</th>`).join('')}</tr>${trs}</table></body></html>`,'application/vnd.ms-excel')}
function reportFileName(j){let desc=slug((j.scope||reportTitle(j)||'service-report').slice(0,45));return `${j.ticketId}_${desc}_Final_Signed_Report.pdf`}
function shareWhatsApp(id){let j=findJob(id);if(!j)return;if(!canShareReport(j)){toast('Customer sign-off is required before sharing final report.');return} if(!j.finalSharedAt){j.status='Report Shared';j.finalSharedAt=now();j.history=j.history||[];j.history.unshift({at:now(),by:current.name,action:'Final signed report shared by WhatsApp'});saveLocal();syncJob(j)}let txt=`Dear Customer,\n\nPlease find the final signed service report softcopy.\n\nFile Name: ${reportFileName(j)}\nTicket: ${j.ticketId}\nCustomer: ${j.customerName}\nSite: ${j.siteName}\nType: ${j.type}\nSystems: ${(j.systems||[]).join(', ')}\n\nRegards,\nPayaswini Integrated Solutions`;window.open('https://wa.me/?text='+encodeURIComponent(txt),'_blank')}
function shareEmail(id){let j=findJob(id);let sub=`Final Signed Service Report - ${j.ticketId}`;let body=`Dear Team,\n\nPlease find the final signed service report softcopy attached / shared.\nFile Name: ${reportFileName(j)}\n\n\nTicket: ${j.ticketId}\nCustomer: ${j.customerName}\nSite: ${j.siteName}\nType: ${j.type}\nSystems: ${(j.systems||[]).join(', ')}\nStatus: ${j.status}\nEngineer: ${j.assignedToName}\n\nRegards,\nPayaswini Integrated Solutions`;location.href=`mailto:?subject=${encodeURIComponent(sub)}&body=${encodeURIComponent(body)}`}
function renderMasters(el){setTitle('Libraries','Users, customers, sites, checklist, material, vendor and service libraries');let tabs=['customers','sites','users','checklists','materials','vendors','contacts','services'];el.innerHTML=`<div class="libraryHero"><div><span class="eyebrow">MASTER DATA CENTER</span><h2>FieldOps Libraries</h2><p>Maintain clean master data so tickets, reports and proposals are generated without duplicate typing.</p></div></div><div class="tabs">${tabs.map(t=>`<button class="btn tab ${activeMaster===t?'active':''}" onclick="activeMaster='${t}';render()">${t[0].toUpperCase()+t.slice(1)}</button>`).join('')}</div><div id="masterOut">${masterHtml()}</div>`}
function masterHtml(){
 if(activeMaster==='customers')return `<div class="card"><h3>Customer Library</h3><p class="muted">Used in job creation, report output and proposal creation.</p><div class="grid four"><input id="m_customer" placeholder="Customer name"><input id="m_contact" placeholder="Primary contact"><input id="m_email" placeholder="Email"><input id="m_phone" placeholder="Phone"></div><button class="btn ok" onclick="addCustomer()">Add Customer</button>${simpleTable(['Customer','Contact','Email','Phone'],state.customers.map(c=>[c.name,c.contact||'',c.email||'',c.phone||'']))}</div>`;
 if(activeMaster==='sites')return `<div class="card"><h3>Site Library</h3><p class="muted">Link every site to a customer for faster dispatch and proposal preparation.</p><div class="grid four"><input id="m_site_customer" list="mCustList" placeholder="Customer"><datalist id="mCustList">${state.customers.map(c=>`<option value="${esc(c.name)}">`).join('')}</datalist><input id="m_site" placeholder="Site name"><input id="m_addr" placeholder="Address"><input id="m_city" placeholder="City"></div><button class="btn ok" onclick="addSite()">Add Site</button>${simpleTable(['Customer','Site','Address','City'],state.sites.map(s=>[s.customerName,s.name,s.address||'',s.city||'']))}</div>`;
 if(activeMaster==='users')return `<div class="card"><h3>User Management</h3><p class="muted">Admin can edit default and newly added users. Assignment dropdowns use this library.</p><div class="grid four"><input id="m_uname" placeholder="Username"><input id="m_name" placeholder="Full name"><select id="m_role"><option>Engineer</option><option>Supervisor</option><option>Coordinator</option><option>Admin</option></select><select id="m_active"><option value="true">Active</option><option value="false">Inactive</option></select></div><div class="grid three"><input id="m_pw" placeholder="Temporary password"><input id="m_mobile" placeholder="Mobile"><input id="m_email_user" placeholder="Email"></div><button class="btn ok" onclick="addUser()">Add User</button>${userManagementTable()}</div>`;
 if(activeMaster==='materials')return `<div class="card"><h3>Material Library</h3><p class="muted">Used for report material consumption and proposal line items.</p><div class="grid four"><input id="m_mat" placeholder="Material / Item"><input id="m_mat_cat" placeholder="Category"><select id="m_mat_uom"><option>Nos</option><option>Mtr</option><option>Lot</option><option>Set</option><option>Job</option></select><input id="m_mat_rate" type="number" placeholder="Default rate"></div><button class="btn ok" onclick="addMaterialMaster()">Add Material</button>${simpleTable(['Item','Category','UOM','Default Rate'],state.materials.map(m=>[m.name,m.category||'',m.uom||'',m.rate||'']))}</div>`;
 if(activeMaster==='vendors')return `<div class="card"><h3>Vendor / Make Library</h3><p class="muted">Useful for approved make lists and proposal outputs.</p><div class="grid three"><input id="m_vendor" placeholder="Make / Vendor"><input id="m_vendor_cat" placeholder="Category / System"><input id="m_vendor_contact" placeholder="Contact / Remarks"></div><button class="btn ok" onclick="addVendor()">Add Vendor</button>${simpleTable(['Vendor / Make','Category','Contact / Remarks'],state.vendors.map(v=>[v.name,v.category||'',v.contact||'']))}</div>`;
 if(activeMaster==='contacts')return `<div class="card"><h3>Customer Contact Library</h3><p class="muted">Stores FM/contact persons for report sign-off and proposal communication.</p><div class="grid four"><input id="m_ct_customer" list="mCustList2" placeholder="Customer"><datalist id="mCustList2">${state.customers.map(c=>`<option value="${esc(c.name)}">`).join('')}</datalist><input id="m_ct_name" placeholder="Name"><input id="m_ct_desig" placeholder="Designation"><input id="m_ct_email" placeholder="Email / Mobile"></div><button class="btn ok" onclick="addContact()">Add Contact</button>${simpleTable(['Customer','Name','Designation','Contact'],state.contacts.map(c=>[c.customerName,c.name,c.designation||'',c.contact||'']))}</div>`;
 if(activeMaster==='services')return `<div class="card"><h3>Service Category Library</h3><p class="muted">Controls job/proposal classification.</p><div class="grid two"><input id="m_service" placeholder="Service category"><button class="btn ok" onclick="addServiceCategory()">Add Category</button></div>${state.serviceCategories.map(s=>`<span class="pill">${esc(s)}</span>`).join('')}</div>`;
 return `<div class="card"><h3>Checklist Library Editor</h3><p class="muted">Default system-wise and job-specific templates. Every new ticket copies from this library and can still be customized ticket-wise.</p><div class="grid three"><select id="lib_system">${SYSTEMS.map(s=>`<option>${esc(s)}</option>`).join('')}</select><select id="lib_mode"><option value="service">Service / Breakdown</option><option value="pm">PM / Inspection</option></select><input id="lib_item" placeholder="Checklist point"></div><button class="btn ok" onclick="addLibItem()">Add Checklist Point</button>${Object.keys(state.checklistLibrary).map(s=>`<details class="card"><summary><b>${esc(s)}</b></summary><div class="grid two"><div><h4>Service / Breakdown</h4><ol>${(state.checklistLibrary[s].service||[]).map((x,i)=>`<li>${esc(x)} <button class="btn small bad" onclick="removeLibItem('${esc(s)}','service',${i})">Remove</button></li>`).join('')}</ol></div><div><h4>PM / Inspection</h4><ol>${(state.checklistLibrary[s].pm||[]).map((x,i)=>`<li>${esc(x)} <button class="btn small bad" onclick="removeLibItem('${esc(s)}','pm',${i})">Remove</button></li>`).join('')}</ol></div></div></details>`).join('')}</div>`;
}

function userManagementTable(){
 const canEdit=current?.role==='Admin';
 return `<div class="tablewrap"><table><thead><tr><th>Name</th><th>Username</th><th>Role</th><th>Mobile</th><th>Email</th><th>Active</th><th>Action</th></tr></thead><tbody>${state.users.map(u=>`<tr>
  <td>${canEdit?`<input id="eu_name_${u.id}" value="${esc(u.name)}">`:esc(u.name)}</td>
  <td>${canEdit?`<input id="eu_username_${u.id}" value="${esc(u.username)}">`:esc(u.username)}</td>
  <td>${canEdit?`<select id="eu_role_${u.id}">${['Admin','Coordinator','Supervisor','Engineer'].map(r=>`<option ${u.role===r?'selected':''}>${r}</option>`).join('')}</select>`:esc(u.role)}</td>
  <td>${canEdit?`<input id="eu_mobile_${u.id}" value="${esc(u.mobile||'')}">`:esc(u.mobile||'')}</td>
  <td>${canEdit?`<input id="eu_email_${u.id}" value="${esc(u.email||'')}">`:esc(u.email||'')}</td>
  <td>${canEdit?`<select id="eu_active_${u.id}"><option value="true" ${u.active!==false?'selected':''}>Yes</option><option value="false" ${u.active===false?'selected':''}>No</option></select>`:(u.active!==false?'Yes':'No')}</td>
  <td>${canEdit?`<button class="btn small ok" onclick="updateUser('${u.id}')">Save</button> <button class="btn small bad" onclick="deleteUser('${u.id}')">Delete</button>`:'-'}</td>
 </tr>`).join('')}</tbody></table></div>`;
}
function updateUser(id){
 if(current?.role!=='Admin'){toast('Only Admin can edit users.');return}
 let u=state.users.find(x=>x.id===id); if(!u)return;
 u.name=$('eu_name_'+id)?.value.trim()||u.name;
 u.username=($('eu_username_'+id)?.value.trim().toLowerCase()||u.username);
 u.role=$('eu_role_'+id)?.value||u.role;
 u.mobile=$('eu_mobile_'+id)?.value.trim()||'';
 u.email=$('eu_email_'+id)?.value.trim()||'';
 u.active=($('eu_active_'+id)?.value!=='false');
 u.updatedAt=now();
 if(current.id===id){current={...current,...u};$('who').textContent=current.name;$('role').textContent=current.role;buildNav();}
 saveLocal();toast('User updated.');render();
}
function deleteUser(id){
 if(current?.role!=='Admin'){toast('Only Admin can delete users.');return}
 if(current.id===id){toast('You cannot delete the logged-in user.');return}
 if(state.jobs.some(j=>j.assignedToId===id)&&!confirm('This user has assigned tickets. Mark inactive instead?'))return;
 state.users=state.users.filter(u=>u.id!==id);saveLocal();toast('User deleted.');render();
}

function simpleTable(head,rows){return `<div class="tablewrap"><table><thead><tr>${head.map(h=>`<th>${esc(h)}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${r.map(c=>`<td>${esc(c)}</td>`).join('')}</tr>`).join('')}</tbody></table></div>`}
function addCustomer(){let name=$('m_customer').value.trim();if(name&&!state.customers.some(c=>c.name.toLowerCase()===name.toLowerCase()))state.customers.push({id:'cust_'+slug(name),name,contact:$('m_contact').value,email:$('m_email').value,phone:$('m_phone')?.value||''});saveLocal();render()}
function addSite(){let customerName=$('m_site_customer').value.trim(),name=$('m_site').value.trim();if(customerName&&name)state.sites.push({id:'site_'+slug(customerName+'_'+name),customerName,name,address:$('m_addr').value,city:$('m_city')?.value||''});saveLocal();render()}
function addUser(){let username=$('m_uname').value.trim().toLowerCase(),name=$('m_name').value.trim(); if(!username||!name)return; state.users.push({id:'u_'+slug(username),username,password:$('m_pw').value||'123456',name,role:$('m_role').value,active:$('m_active')?.value!=='false',mobile:$('m_mobile')?.value||'',email:$('m_email_user')?.value||''});saveLocal();render()}
function addLibItem(){let s=$('lib_system').value,m=$('lib_mode').value,t=$('lib_item').value.trim(); if(!t)return; state.checklistLibrary[s]=state.checklistLibrary[s]||{service:[],pm:[]}; state.checklistLibrary[s][m].push(t);saveLocal();render()}
function removeLibItem(s,m,i){state.checklistLibrary[s][m].splice(i,1);saveLocal();render()}
function addMaterialMaster(){let name=$('m_mat').value.trim();if(!name)return;state.materials.push({id:'mat_'+slug(name),name,category:$('m_mat_cat').value,uom:$('m_mat_uom').value,rate:$('m_mat_rate').value});saveLocal();render()}
function addVendor(){let name=$('m_vendor').value.trim();if(!name)return;state.vendors.push({id:'ven_'+slug(name),name,category:$('m_vendor_cat').value,contact:$('m_vendor_contact').value});saveLocal();render()}
function addContact(){let name=$('m_ct_name').value.trim();if(!name)return;state.contacts.push({id:'ct_'+slug(name+Date.now()),customerName:$('m_ct_customer').value,name,designation:$('m_ct_desig').value,contact:$('m_ct_email').value});saveLocal();render()}
function addServiceCategory(){let name=$('m_service').value.trim();if(name&&!state.serviceCategories.includes(name))state.serviceCategories.push(name);saveLocal();render()}

function renderNotifications(el){setTitle('Notifications','Minimal actionable alerts');let ns=state.notifications.filter(n=>!n.toIds||n.toIds.includes(current.id)||current.role==='Admin');el.innerHTML=`<div class="card"><div class="sectionTitle"><div><h3>Notification Center</h3><p class="muted">Default profile is Minimal: only ticket assignments, reassignments, escalations, customer approvals and closures.</p></div><span class="pill ok">${esc(state.settings.notificationProfile||'minimal')}</span></div>${ns.map(n=>`<div class="card notice ${esc(n.type||'')}"><b>${esc(n.title)}</b><p>${esc(n.message)}</p><span class="muted">${esc((n.createdAt||'').replace('T',' ').slice(0,16))}</span></div>`).join('')||'<div class="empty">No notifications.</div>'}</div>`}
function renderProposal(el){setTitle('Proposal Studio','User-friendly proposal creation with templates and professional output');let ref=`PISL/PROP/${new Date().getFullYear()}-${String(new Date().getFullYear()+1).slice(-2)}/${String(Date.now()).slice(-4)}`; el.innerHTML=`<div class="proposalStudio"><div class="proposalHero compactHero"><div><span class="eyebrow">PROPOSAL STUDIO</span><h2>Proposal Wizard</h2><p>1 Customer → 2 Scope → 3 Commercials → 4 Preview/PDF</p></div><div class="heroActions"><button class="btn secondary" onclick="addProposalRow()">+ Item</button><button class="btn ok" onclick="makeProposal()">Preview</button></div></div><div class="wizardSteps noPrint"><span class="on">Customer</span><span>Scope</span><span>Commercials</span><span>Preview</span></div><div class="grid two"><div class="card"><h3>1. Proposal Details</h3><div class="grid two"><div><label>Proposal Type</label><select id="pr_type" onchange="applyProposalType()">${PROPOSAL_TYPES.map(x=>`<option>${x}</option>`).join('')}</select></div><div><label>Reference No.</label><input id="pr_ref" value="${ref}"></div></div><div class="grid two"><div><label>Customer</label><input id="pr_customer" list="customersList2" onchange="proposalSiteList()"><datalist id="customersList2">${state.customers.map(c=>`<option value="${esc(c.name)}">`).join('')}</datalist></div><div><label>Site</label><input id="pr_site" list="proposalSites"><datalist id="proposalSites">${state.sites.map(s=>`<option value="${esc(s.name)}">`).join('')}</datalist></div></div><label>Subject</label><input id="pr_subject" value="Service / Maintenance Proposal"><div class="grid two"><div><label>Validity</label><input id="pr_validity" value="30 days"></div><div><label>Prepared By</label><input id="pr_prepared" value="${esc(current?.name||'Payaswini')}"></div></div></div><div class="card"><h3>2. Scope & Terms</h3><label>Scope of Work</label><textarea id="pr_scope">Scope shall be limited to the systems/items listed in this proposal.</textarea><label>Exclusions / Notes</label><textarea id="pr_exclusions">Any additional scope, concealed work, civil work, electrical power, client-side IT/network dependencies and consumables are excluded unless specifically mentioned.</textarea><label>Terms & Conditions</label><textarea id="pr_terms">${TERMS['AMC Proposal']}</textarea></div></div><div class="card"><div class="sectionTitle"><div><h3>3. Commercial Items</h3><p class="muted">Use material library items or type custom descriptions.</p></div><button class="btn small secondary" onclick="addProposalRow()">+ Add Item</button></div><datalist id="materialList">${(state.materials||[]).map(m=>`<option value="${esc(m.name)}">`).join('')}</datalist><div id="prItems">${proposalItemRow(0)}</div><div class="grid four"><div><label>GST %</label><input id="pr_gst" type="number" value="18"></div><div><label>Discount</label><input id="pr_discount" type="number" value="0"></div><div><label>Payment Terms</label><input id="pr_payment" value="Quarterly in advance / As mutually agreed"></div><div><label>Delivery / Completion</label><input id="pr_delivery" value="As mutually agreed after PO"></div></div><div class="actions"><button class="btn ok" onclick="makeProposal()">Generate Professional Preview</button><button class="btn secondary" onclick="saveProposalDraft()">Save Draft</button></div></div><div id="proposalOut"></div></div>`}
function proposalSiteList(){let c=$('pr_customer')?.value||'';let dl=$('proposalSites');if(dl)dl.innerHTML=state.sites.filter(s=>!c||s.customerName===c).map(s=>`<option value="${esc(s.name)}">`).join('')}
function saveProposalDraft(){makeProposal(true);toast('Proposal draft saved locally')}
function proposalItemRow(i){return `<div class="checkRow prRow proposalRow" style="grid-template-columns:2fr 90px 120px 100px 36px"><input class="prDesc" list="materialList" placeholder="Description / Scope item"><input class="prQty" placeholder="Qty" type="number" value="1"><input class="prRate" placeholder="Rate" type="number"><select class="prUom"><option>Nos</option><option>Lot</option><option>Job</option><option>Mtr</option><option>Set</option><option>Visit</option><option>Quarter</option></select><button class="remove" onclick="this.closest('.prRow').remove()">×</button></div>`}
function addProposalRow(){let d=document.createElement('div');d.innerHTML=proposalItemRow(document.querySelectorAll('.prRow').length);$('prItems').appendChild(d.firstChild)}
function applyProposalType(){let t=$('pr_type').value;$('pr_terms').value=TERMS[t]||TERMS['Service Quotation'];$('pr_subject').value=t}
function makeProposal(saveDraft=false){let rows=[...document.querySelectorAll('.prRow')].map((r,i)=>({i:i+1,desc:r.querySelector('.prDesc').value,qty:Number(r.querySelector('.prQty').value||0),rate:Number(r.querySelector('.prRate').value||0),uom:r.querySelector('.prUom').value})).filter(x=>x.desc); if(!rows.length){toast('Add at least one commercial item.');return} let sub=rows.reduce((a,b)=>a+b.qty*b.rate,0),disc=Number($('pr_discount').value||0),gstp=Number($('pr_gst').value||0),tax=(sub-disc)*gstp/100,total=sub-disc+tax; let prop={id:'prop_'+slug($('pr_ref').value),ref:$('pr_ref').value,type:$('pr_type').value,customer:$('pr_customer').value,site:$('pr_site').value,subject:$('pr_subject').value,total,createdAt:now(),createdBy:current?.name||''}; state.proposals=state.proposals.filter(p=>p.id!==prop.id); state.proposals.unshift(prop); saveLocal(); let html=`<div class="reportPaper proReport proposalDoc"><div class="proposalCover"><div class="reportHeaderBand"><div class="brandReport"><img src="assets/logo.png" alt="Payaswini Integrated Solutions"><div><h1>${esc($('pr_type').value)}</h1><p>Commercial & Technical Submission</p></div></div><div class="ticketBox"><span>Reference</span><b>${esc($('pr_ref').value)}</b><small>Date: ${new Date().toLocaleDateString()}</small></div></div><div class="proposalSubject"><h2>${esc($('pr_subject').value)}</h2><p>Prepared for <b>${esc($('pr_customer').value)}</b> • ${esc($('pr_site').value)}</p></div></div><div class="reportSummary"><div><b>Customer</b><span>${esc($('pr_customer').value)}</span></div><div><b>Site</b><span>${esc($('pr_site').value)}</span></div><div><b>Validity</b><span>${esc($('pr_validity').value)}</span></div><div><b>Prepared By</b><span>${esc($('pr_prepared').value)}</span></div><div><b>Payment Terms</b><span>${esc($('pr_payment').value)}</span></div><div><b>Delivery / Completion</b><span>${esc($('pr_delivery').value)}</span></div></div><h3>Scope of Work</h3><p class="reportBoxText">${esc($('pr_scope').value).replace(/\n/g,'<br>')}</p><h3>Commercial Offer</h3><table class="proposalTable"><thead><tr><th>Sr</th><th>Description</th><th>Qty</th><th>UOM</th><th>Rate</th><th>Amount</th></tr></thead><tbody>${rows.map(x=>`<tr><td>${x.i}</td><td>${esc(x.desc)}</td><td>${x.qty}</td><td>${esc(x.uom)}</td><td>${money(x.rate)}</td><td>${money(x.qty*x.rate)}</td></tr>`).join('')}<tr><th colspan="5">Sub Total</th><th>${money(sub)}</th></tr><tr><th colspan="5">Discount</th><th>${money(disc)}</th></tr><tr><th colspan="5">GST ${gstp}%</th><th>${money(tax)}</th></tr><tr class="grand"><th colspan="5">Grand Total</th><th>₹ ${money(total)}</th></tr></tbody></table><h3>Exclusions / Notes</h3><p class="reportBoxText">${esc($('pr_exclusions').value).replace(/\n/g,'<br>')}</p><h3>Terms & Conditions</h3><p class="reportBoxText">${esc($('pr_terms').value).replace(/\n/g,'<br>')}</p><div class="signrow"><div class="sig"><b>For Payaswini Integrated Solutions</b><br>Authorized Signatory</div><div class="sig"><b>Client Confirmation</b><br>Name / Signature / Seal</div></div><div class="reportFooter">Generated from PISL FieldOps Enterprise v40.5 • ${esc($('pr_ref').value)}</div><div class="actions noPrint"><button class="btn" onclick="printProposal()">Export / Save PDF</button><button class="btn secondary" onclick="downloadProposalExcel()">Export Excel</button><button class="btn secondary" onclick="window.scrollTo({top:0,behavior:'smooth'})">Edit Proposal</button></div></div>`; $('proposalOut').innerHTML=html; window.__lastProposalHtml=html; window.__lastProposalRows=rows; window.__lastProposalRef=$('pr_ref').value; toast(saveDraft?'Proposal draft saved and preview generated.':'Proposal preview generated.');}
function downloadProposalExcel(){let rows=window.__lastProposalRows||[]; if(!rows.length){toast('Generate proposal first.');return} let trs=rows.map(x=>`<tr><td>${x.i}</td><td>${excelCell(x.desc)}</td><td>${x.qty}</td><td>${excelCell(x.uom)}</td><td>${x.rate}</td><td>${x.qty*x.rate}</td></tr>`).join('');downloadFile(`${slug(window.__lastProposalRef||'proposal')}_commercial.xls`,`<html><head><meta charset="utf-8"></head><body><h2>Proposal Commercial - ${excelCell(window.__lastProposalRef||'')}</h2><table border="1"><tr><th>Sr</th><th>Description</th><th>Qty</th><th>UOM</th><th>Rate</th><th>Amount</th></tr>${trs}</table></body></html>`,'application/vnd.ms-excel')}
function printProposal(){let html=window.__lastProposalHtml||$('proposalOut').innerHTML;if(!html){toast('Generate proposal preview first.');return}let w=window.open('','_blank');w.document.write(`<!doctype html><html><head><title>${esc(window.__lastProposalRef||'Proposal')}</title><link rel="stylesheet" href="${new URL('css/main.css',location.href).href}"></head><body>${html.replaceAll('src="assets/logo.png"','src="'+new URL('assets/logo.png',location.href).href+'"')}<script>setTimeout(()=>print(),700)<\/script></body></html>`);w.document.close()}

function secureToken(){let a=new Uint8Array(16);try{crypto.getRandomValues(a);return [...a].map(x=>x.toString(16).padStart(2,'0')).join('').toUpperCase()}catch(e){return (Date.now().toString(36)+Math.random().toString(36).slice(2,14)).toUpperCase()}}
function signoffUrl(j){return location.origin+location.pathname+'?signoff='+encodeURIComponent(j.ticketId)+'&token='+encodeURIComponent(j.signoffToken||'')}
async function createSignoffLink(id){let j=findJob(id);if(!j)return;completeReport(id,true);if(j.signoffApproved){toast('This report is already signed. Link is expired after approval.');return}if(!j.signoffToken)j.signoffToken=secureToken();j.status='Customer Sign-off';j.signoffRequestedAt=now();j.history=j.history||[];j.history.unshift({at:now(),by:current.name,action:'Customer sign-off link generated'});saveLocal();await syncJob(j);let url=signoffUrl(j);try{await navigator.clipboard.writeText(url);toast('Secure customer sign-off link copied. Link expires after approval.')}catch(e){prompt('Copy secure customer sign-off link',url)}render();}
function customerSignoffBlock(j){if(!j.signoffApproved)return `<div class="signoffNotice"><b>Customer Digital Sign-off</b><span>Pending. Final sharing is locked until customer approval.</span></div>`;return `<div class="signedSeal"><b>Digitally Signed by Customer</b><span>Name: ${esc(j.customerSignoff?.name||'Customer')}</span><span>Designation: ${esc(j.customerSignoff?.designation||'')}</span><span>Signed At: ${esc((j.customerSignoff?.signedAt||'').replace('T',' ').slice(0,16))}</span></div>`}
function reportSignatureSection(j){let cust=j.customerSignoff||{};let sig=cust.signature?`<img class="sigImg" src="${cust.signature}">`:'<br><br>';let esig=j.engineerSignature?`<img class="sigImg" src="${j.engineerSignature}">`:'<br><br>';return `<div class="signrow"><div class="sig signed"><b>Digitally Signed by Engineer</b><br>${esig}<br>Name: ${esc(j.engineerSignedBy||j.assignedToName||'')}<br>Date/Time: ${esc((j.engineerSignedAt||j.reportCompletedAt||j.updatedAt||'').replace('T',' ').slice(0,16))}</div><div class="sig signed"><b>Digitally Signed by Customer</b><br>${sig}<br>Name: ${esc(cust.name||'Pending')}<br>Designation: ${esc(cust.designation||'')}<br>Date/Time: ${esc((cust.signedAt||'Pending').replace('T',' ').slice(0,16))}</div></div>`}
async function loadSignoffJob(ticket,token){let local=state.jobs.find(j=>j.ticketId===ticket&&j.signoffToken===token); if(local)return local; if(cloudReady&&db){let qs=await db.collection('jobs').where('ticketId','==',ticket).limit(1).get(); if(!qs.empty){let j=normalizeJob({firestoreId:qs.docs[0].id,...qs.docs[0].data()});let i=state.jobs.findIndex(x=>x.ticketId===j.ticketId); if(i>=0)state.jobs[i]=j; else state.jobs.unshift(j);saveLocal();return j}} return null}
async function renderCustomerSignoffPortal(){document.body.innerHTML='<div id="toast" class="toast hidden"></div><section id="signoffPortal" class="signoffPortal"><div class="card"><h2>Loading secure report...</h2></div></section>';let q=new URLSearchParams(location.search),ticket=q.get('signoff'),token=q.get('token');let j=await loadSignoffJob(ticket,token);let root=document.getElementById('signoffPortal');if(!j||!token||j.signoffToken!==token){root.innerHTML='<div class="card signoffCard"><h2>Invalid Report Link</h2><p>This secure report link is invalid or not available.</p></div>';return}if(j.signoffApproved){root.innerHTML=`<div class="card signoffCard"><h2>Report Already Approved</h2><p>The secure link for <b>${esc(j.ticketId)}</b> has expired after customer approval.</p></div>`;return}root.innerHTML=`<div class="signoffWrap"><div class="signoffTop"><img src="assets/logo.png"><div><h1>Customer Report Review & Digital Sign-off</h1><p>Only this report is accessible. Engineer data is read-only.</p></div></div>${reportHtml(j).replace(/<div class="actions noPrint">[\s\S]*?<\/div><\/div>$/,'</div>')}<div class="card signoffForm"><h2>Approve This Report</h2><p class="muted">Please review the full report above. You can only approve/sign; you cannot edit report content.</p><div class="grid two"><div><label>Customer Name *</label><input id="so_name" placeholder="Name"></div><div><label>Designation *</label><input id="so_desig" placeholder="Designation"></div></div><label>Digital Signature *</label><canvas id="sigCanvas" class="sigCanvas" width="620" height="210"></canvas><div class="actions"><button class="btn secondary" onclick="clearSig()">Clear Signature</button><button class="btn ok" onclick="submitCustomerSignoff('${esc(j.id)}')">Submit Approval & Lock Report</button></div></div></div>`;initSigCanvas();}
let sigDirty=false;
function initSigCanvas(){let c=document.getElementById('sigCanvas');if(!c)return;let ctx=c.getContext('2d'),drawing=false,last=null;ctx.lineWidth=2.5;ctx.lineCap='round';function pos(e){let r=c.getBoundingClientRect(),t=e.touches?e.touches[0]:e;return{x:(t.clientX-r.left)*c.width/r.width,y:(t.clientY-r.top)*c.height/r.height}}function start(e){drawing=true;last=pos(e);e.preventDefault()}function move(e){if(!drawing)return;let p=pos(e);ctx.beginPath();ctx.moveTo(last.x,last.y);ctx.lineTo(p.x,p.y);ctx.stroke();last=p;sigDirty=true;e.preventDefault()}function end(){drawing=false}c.addEventListener('mousedown',start);c.addEventListener('mousemove',move);window.addEventListener('mouseup',end);c.addEventListener('touchstart',start,{passive:false});c.addEventListener('touchmove',move,{passive:false});c.addEventListener('touchend',end)}
function clearSig(){let c=document.getElementById('sigCanvas');if(c)c.getContext('2d').clearRect(0,0,c.width,c.height);sigDirty=false}
async function submitCustomerSignoff(id){let j=findJob(id);if(!j)return;let name=document.getElementById('so_name').value.trim(),desig=document.getElementById('so_desig').value.trim(),c=document.getElementById('sigCanvas');if(!name||!desig){alert('Customer name and designation are required.');return}if(!sigDirty){alert('Digital signature is required.');return}j.signoffApproved=true;j.signoffToken=null;j.status='Customer Signed';j.customerSignoff={name,designation:desig,signature:c.toDataURL('image/png'),signedAt:now(),method:'Secure report link'};j.history=j.history||[];j.history.unshift({at:now(),by:name,action:'Customer digitally signed the report'});saveLocal();await syncJob(j);document.getElementById('signoffPortal').innerHTML=`<div class="card signoffCard"><h2>Thank you</h2><p>Report <b>${esc(j.ticketId)}</b> has been digitally signed and locked.</p><p>The secure link is now expired after approval.</p></div>`}

function renderAdmin(el){setTitle('Administration','Configuration, backup and maintenance');let fcmReady=!!(window.FCM_PUBLIC_VAPID_KEY||'').trim();el.innerHTML=`<div class="grid two"><div class="card"><h3>Push Notification Status</h3><p class="muted">Important alerts only. Firebase project settings are kept in <b>js/firebase-config.js</b>. VAPID key is not shown in the user screen.</p><p>${fcmReady?'<span class="pill ok">FCM Configured</span>':'<span class="pill warn">FCM Backend Key Pending</span>'}</p><button class="btn ok" onclick="enableFCM()">Enable Important Alerts on This Device</button>${!fcmReady?'<p class="muted">If the VAPID key is blank, this will safely skip push setup without breaking the app.</p>':''}</div><div class="card"><h3>Notification Profile</h3><p class="muted">Minimal is recommended to avoid annoying alerts.</p><select id="notifProfile" onchange="setNotificationProfile(this.value)"><option value="minimal" ${state.settings.notificationProfile==='minimal'?'selected':''}>Minimal - assignments, reassignments, escalations, approvals and closures</option><option value="standard" ${state.settings.notificationProfile==='standard'?'selected':''}>Standard - critical workflow milestones</option><option value="verbose" ${state.settings.notificationProfile==='verbose'?'selected':''}>Verbose - testing/debug only</option></select></div><div class="card"><h3>Maintenance</h3><button class="btn secondary" onclick="backupJson()">Backup JSON</button><button class="btn warn" onclick="state.notifications=[];saveLocal();render()">Clear Local Notifications</button><button class="btn bad" onclick="if(confirm('Clear closed local jobs?')){state.jobs=state.jobs.filter(j=>j.status!=='Closed');saveLocal();render()}">Purge Closed Local Jobs</button></div><div class="card"><h3>Build Scope</h3><p>Included: minimal actionable alerts, complete libraries, guided workflow, install-ready PWA, job control room, checklist editor, ticket reports, proposal studio, FCM-ready backend config, photo evidence, customer sign-off and WhatsApp/email sharing.</p><p>Excluded: Attendance, GPS, QR, SLA and asset history.</p></div></div>`}
function setNotificationProfile(v){state.settings.notificationProfile=v;saveLocal();toast('Notification profile set to '+v)}
async function enableFCM(fromInstall=false){try{let vapid=(window.FCM_PUBLIC_VAPID_KEY||'').trim(); if(!('Notification' in window)){toast('Notifications are not supported in this browser.');setInstallStatus('Notifications are not supported in this browser.','warn');return false} if(!vapid){let m='App install is ready. Push backend key is pending in js/firebase-config.js, so alerts will activate after the key is added.';toast('Push backend key pending. App is still usable.');setInstallStatus(m,'warn');return false} if(!messaging){toast('FCM is not available on this browser/device.');setInstallStatus('FCM is not available on this browser/device.','warn');return false}let perm=Notification.permission==='granted'?'granted':await Notification.requestPermission(); if(perm!=='granted'){toast('Notification permission not granted.');setInstallStatus('Notification permission was not granted. You can enable it later from browser settings.','warn');return false}let reg=await navigator.serviceWorker.ready;let token=await messaging.getToken({vapidKey:vapid,serviceWorkerRegistration:reg});let userId=current?.id||'login_device';let name=current?.name||'Login Device';let role=current?.role||'Pre-login';state.pushTokens=state.pushTokens.filter(t=>t.token!==token);state.pushTokens.push({token,userId,name,role,createdAt:now(),source:fromInstall?'install':'manual'});saveLocal(); if(cloudReady&&db)await db.collection('pushTokens').doc(userId+'_'+slug(token.slice(-12))).set({token,userId,name,role,updatedAt:now(),source:fromInstall?'install':'manual'},{merge:true});toast('Push notifications enabled for this device.');setInstallStatus('Push notifications enabled for this device.','ok');return true}catch(e){console.warn('FCM enable skipped',e);toast('Push notification setup skipped. App is still usable.');setInstallStatus('Push notification setup could not be completed on this device.','warn');return false}}
async function installAndEnablePush(){try{setInstallStatus('Preparing app installation...','info'); if(deferredPrompt){deferredPrompt.prompt();let choice=await deferredPrompt.userChoice;deferredPrompt=null;if(choice&&choice.outcome==='accepted'){setInstallStatus('App installation accepted. Enabling push alerts...','ok'); await enableFCM(true);}else{setInstallStatus('Installation was dismissed. You can install later from this button/browser menu.','warn');}}else if(isStandalone()){setInstallStatus('App is already installed. Enabling push alerts...','ok'); await enableFCM(true);}else{setInstallStatus('Install prompt is not available yet. Use browser menu → Install app / Add to Home Screen, then enable push alerts.','warn'); await enableFCM(true);}}catch(e){console.warn('Install failed',e);setInstallStatus('Install/notification setup could not be completed. Try browser menu → Install app.','warn');}}
function notificationAllowed(type){let profile=state.settings?.notificationProfile||'minimal';let minimal=['ticket_assigned','ticket_reassigned','escalated','customer_approved','closed'];let standard=[...minimal,'accepted','checked_in','checked_out','report_sent'];return profile==='verbose'||(profile==='standard'&&standard.includes(type))||minimal.includes(type)}
async function notify(j,msg,type='general'){if(!notificationAllowed(type))return;let n={type,title:'FieldOps',message:msg,toIds:j.visibleTo||[],ticketId:j.ticketId,createdAt:now(),read:false};state.notifications.unshift(n);saveLocal(); if(cloudReady)try{await db.collection('notifications').add(n)}catch(e){}}
function backupJson(){let a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(state,null,2)],{type:'application/json'}));a.download='pisl-fieldops-backup.json';a.click()}
function startRealtime(){if(!cloudReady)return;unsubs.forEach(u=>u());unsubs=[];try{unsubs.push(db.collection('jobs').orderBy('createdAt','desc').limit(300).onSnapshot(s=>{let remote=s.docs.map(d=>normalizeJob({firestoreId:d.id,...d.data()}));remote.forEach(r=>{let i=state.jobs.findIndex(j=>j.firestoreId===r.firestoreId||j.id===r.id); if(i>=0)state.jobs[i]=r; else state.jobs.unshift(r)});saveLocal(); if(!$('login').classList.contains('hidden'))return; render();}));unsubs.push(db.collection('notifications').orderBy('createdAt','desc').limit(100).onSnapshot(s=>{state.notifications=s.docs.map(d=>({firestoreId:d.id,...d.data()}));saveLocal(); if(activeView==='notifications'||activeView==='dashboard')render()}))}catch(e){console.warn('Realtime not available',e)}}
window.addEventListener('beforeinstallprompt',e=>{e.preventDefault();deferredPrompt=e;setInstallStatus('App installation is available. Tap Install App + Enable Important Alerts.','ok')});
window.addEventListener('appinstalled',()=>{setInstallStatus('App installed successfully. Enabling push alerts...','ok');enableFCM(true)});
if('serviceWorker'in navigator)navigator.serviceWorker.register('service-worker.js').catch(console.warn);
window.onload=loadLocal;
